import { ObjectId } from 'mongodb';

export class CreateGroupDTO {
  name: string;
  description: string;
  adminId: ObjectId;
  members: ObjectId[];
  telegramChatId?: string;
}

export class GroupResponseDTO {
  id: ObjectId;
  name: string;
  description: string;
  adminId: ObjectId;
  members: ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

import { z } from 'zod';

export const createGroupValidator = z.object({
  name: z.string().min(1),
  description: z.string().optional(),
});

export const linkTelegramValidator = z.object({
  telegramChatId: z.string().min(1),
});

import { ObjectId } from 'mongodb';
import { Group } from '../../types/group.model';
import { getDb } from '../../utils/database';

export class GroupRepository {
  private collection = getDb().collection<Group>('groups');

  async createGroup(group: Omit<Group, 'id'>): Promise<Group> {
    const { insertedId } = await this.collection.insertOne(group);
    return { ...group, id: insertedId };
  }

  async findGroupById(id: ObjectId): Promise<Group | null> {
    return this.collection.findOne({ id });
  }

  async updateTelegramChatId(id: ObjectId, telegramChatId: string): Promise<void> {
    await this.collection.updateOne({ id }, { $set: { telegramChatId } });
  }
}

import { ObjectId } from 'mongodb';
import { GroupRepository } from './group.repository';
import { CreateGroupDTO, GroupResponseDTO } from './group.dto';

export class GroupService {
  private repository = new GroupRepository();

  async createGroup(dto: CreateGroupDTO): Promise<GroupResponseDTO> {
    const group = await this.repository.createGroup({ ...dto, adminId: new ObjectId(), members: [], createdAt: new Date() });
    return new GroupResponseDTO(group);
  }

  async linkTelegram(groupId: string, telegramChatId: string): Promise<void> {
    await this.repository.updateTelegramChatId(new ObjectId(groupId), telegramChatId);
  }
}

import { Request, Response } from 'express';
import { GroupService } from './group.service';
import { createGroupValidator, linkTelegramValidator } from './group.validator';

const service = new GroupService();

export const createGroup = async (req: Request, res: Response) => {
  try {
    const validatedData = createGroupValidator.parse(req.body);
    const group = await service.createGroup(validatedData);
    res.status(201).json({ success: true, data: group, meta: {} });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
};

export const linkTelegram = async (req: Request, res: Response) => {
  try {
    const validatedData = linkTelegramValidator.parse(req.body);
    await service.linkTelegram(req.params.id, validatedData.telegramChatId);
    res.status(200).json({ success: true, meta: {} });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
};
